SELECT s.shipment_id, c.compound_name, c.formula, c.purity, c.mw
FROM shipments s
JOIN catalogs c ON s.catalog_id = c.catalog_id;

SELECT catal.compound_name, catal.formula, safety.hazard_class, safety.hazard_statement
FROM catalogs catal
INNER JOIN safety_handling safety ON catal.catalog_id = safety.compound_id;

SELECT c.compound_name, sh.hazard_class 
FROM catalogs c
INNER JOIN safety_handling sh ON c.catalog_id = sh.compound_id;

SELECT catalogs.compound_name, sites.site_name
FROM catalogs
INNER JOIN sites ON catalogs.supplier_id = sites.site_id;

SELECT project_name, start_date, end_date
FROM projects
WHERE end_date > date('now');

SELECT SUM(volume) AS total_volume
FROM wells
WHERE concentration > 100;

SELECT SUM(volume) AS total_volume
FROM shipments
WHERE site_from = (
    SELECT site_id FROM sites WHERE site_name = 'Your Site Name'
);

SELECT compound_name, formula, mw
FROM catalogs
ORDER BY formula ASC;

SELECT shipments.shipment_id, shipments.catalog_id, catalogs.compound_name
FROM shipments
JOIN catalogs ON shipments.catalog_id = catalogs.catalog_id;

SELECT SUM(catalogs.purity) AS TotalPurity
FROM shipments
JOIN catalogs ON shipments.catalog_id = catalogs.catalog_id;
